import { Card, Stack, Row, Text, Divider, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city?: string;
  /** Current temperature */
  temperature?: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition?: string;
  /** Humidity percentage */
  humidity?: number;
  /** Wind speed */
  windSpeed?: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast?: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function WeatherCard({
  city = 'San Francisco',
  temperature = 72,
  condition = 'Sunny',
  humidity = 65,
  windSpeed = 12,
  unit = 'F',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 75, low: 62 },
    { day: 'Tue', icon: '☁️', high: 73, low: 61 },
    { day: 'Wed', icon: '🌧️', high: 68, low: 58 },
    { day: 'Thu', icon: '☀️', high: 76, low: 63 },
    { day: 'Fri', icon: '☀️', high: 78, low: 65 },
  ],
}: Props) {
  return (
    <Card padding={24} shadow="md" border={true}>
      <Stack direction="vertical" gap={20} align="stretch">
        {/* Header: City Name */}
        <Text
          variant="h2"
          color="var(--ggui-color-onSurface, #18181b)"
          weight="bold"
        >
          {city}
        </Text>

        {/* Current Weather Section: Temperature + Icon/Condition */}
        <Row gap={24} align="center" justify="between">
          {/* Temperature Display Box */}
          <Box
            padding="var(--ggui-spacing-6, 24px)"
            background="var(--ggui-color-primary-50, #f0f9ff)"
            borderRadius="var(--ggui-shape-radius-lg, 12px)"
            style={{
              flex: 1,
              textAlign: 'center',
              boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))',
            }}
          >
            <Text
              variant="h1"
              color="var(--ggui-color-primary-900, #0c4a6e)"
              weight="bold"
              align="center"
              style={{
                fontSize: 'var(--ggui-font-size-4xl, 36px)',
              }}
            >
              {temperature}°{unit}
            </Text>
          </Box>

          {/* Weather Icon + Condition */}
          <Stack
            direction="vertical"
            gap={8}
            align="center"
            justify="center"
            style={{ flex: 1 }}
          >
            <Text
              style={{
                fontSize: 'var(--ggui-font-size-3xl, 30px)',
                lineHeight: '1',
              }}
            >
              ☀️
            </Text>
            <Text
              variant="h3"
              color="var(--ggui-color-onSurface, #18181b)"
              weight="semibold"
              align="center"
            >
              {condition}
            </Text>
          </Stack>
        </Row>

        {/* Metrics: Humidity */}
        <Row gap={16} align="center" justify="between">
          <Text
            variant="label"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
            weight="medium"
          >
            Humidity
          </Text>
          <Text
            variant="body"
            color="var(--ggui-color-onSurface, #18181b)"
            weight="semibold"
          >
            {humidity}%
          </Text>
        </Row>

        {/* Metrics: Wind Speed */}
        <Row gap={16} align="center" justify="between">
          <Text
            variant="label"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
            weight="medium"
          >
            Wind Speed
          </Text>
          <Text
            variant="body"
            color="var(--ggui-color-onSurface, #18181b)"
            weight="semibold"
          >
            {windSpeed} mph
          </Text>
        </Row>

        {/* Divider */}
        <Divider orientation="horizontal" margin={16} />

        {/* 5-Day Forecast Section */}
        <Stack direction="vertical" gap={12} align="stretch">
          <Text
            variant="label"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
            weight="medium"
          >
            5-Day Forecast
          </Text>

          {/* Forecast Items Row */}
          <Row
            gap={8}
            align="stretch"
            justify="start"
            wrap={true}
            style={{
              minHeight: '100px',
            }}
          >
            {forecast.map((item, index) => (
              <Box
                key={index}
                padding="var(--ggui-spacing-4, 16px)"
                background="var(--ggui-color-primary-50, #f0f9ff)"
                borderRadius="var(--ggui-shape-radius-md, 8px)"
                style={{
                  flex: '1 1 calc(20% - 8px)',
                  minWidth: '80px',
                  textAlign: 'center',
                  boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))',
                  border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                }}
              >
                <Stack
                  direction="vertical"
                  gap={4}
                  align="center"
                  justify="center"
                >
                  {/* Day Name */}
                  {item.day && (
                    <Text
                      variant="label"
                      color="var(--ggui-color-onSurface, #18181b)"
                      weight="medium"
                    >
                      {item.day}
                    </Text>
                  )}

                  {/* Weather Icon */}
                  {item.icon && (
                    <Text
                      style={{
                        fontSize: 'var(--ggui-font-size-lg, 18px)',
                        lineHeight: '1',
                      }}
                    >
                      {item.icon}
                    </Text>
                  )}

                  {/* High Temperature */}
                  {item.high !== undefined && (
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurface, #18181b)"
                      weight="semibold"
                      style={{
                        marginTop: '4px',
                      }}
                    >
                      {item.high}°
                    </Text>
                  )}

                  {/* Low Temperature */}
                  {item.low !== undefined && (
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    >
                      {item.low}°
                    </Text>
                  )}
                </Stack>
              </Box>
            ))}
          </Row>
        </Stack>
      </Stack>
    </Card>
  );
}

import { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Button,
  Input,
  Select,
  Badge,
  Icon,
  Divider,
} from '@ggui-ai/design/primitives';

interface Task {
  id?: string;
  title?: string;
  priority?: 'low' | 'medium' | 'high';
  assignee?: string;
  column?: string;
  dueDate?: string;
}

interface Column {
  id?: string;
  name?: string;
}

interface Props {
  tasks: Task[];
  columns: Column[];
  onTaskUpdate?: (payload: {
    action: 'move' | 'edit' | 'create';
    taskId?: string;
    data: Record<string, unknown>;
  }) => void;
}

function generateId(): string {
  return Math.random().toString(36).substring(2, 11);
}

function formatDate(dateStr: string): string {
  if (!dateStr) return '';
  const date = new Date(dateStr + 'T00:00:00');
  return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
}

export default function KanbanBoard({
  tasks: propsTasks = [],
  columns = [],
  onTaskUpdate,
}: Props) {
  const [localTasks, setLocalTasks] = useState<Task[]>([]);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState<string>('');
  const [addingColumnId, setAddingColumnId] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState<string>('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formErrors, setFormErrors] = useState<{ title?: string }>({});
  const [successMessage, setSuccessMessage] = useState<string | null>(null);

  useEffect(() => {
    const tasksWithIds = propsTasks.map((task) => ({
      ...task,
      id: task.id || generateId(),
      column: task.column || columns[0]?.id || 'todo',
    }));
    setLocalTasks(tasksWithIds);
  }, [propsTasks, columns]);

  useEffect(() => {
    if (successMessage) {
      const timer = setTimeout(() => setSuccessMessage(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [successMessage]);

  const validateTitle = (title: string) => {
    if (!title || title.trim().length === 0) return 'Title is required';
    return title.length > 255 ? 'Title too long' : '';
  };

  const handleMoveTask = (taskId: string, targetColumnId: string) => {
    setLocalTasks((prev) =>
      prev.map((task) =>
        task.id === taskId ? { ...task, column: targetColumnId } : task
      )
    );
    onTaskUpdate?.({
      action: 'move',
      taskId,
      data: { column: targetColumnId },
    });
  };

  const handleEditStart = (task: Task) => {
    setEditingTaskId(task.id || null);
    setEditingTitle(task.title || '');
    setFormErrors({});
  };

  const handleEditSave = (taskId: string) => {
    const error = validateTitle(editingTitle);
    if (error) {
      setFormErrors({ title: error });
      return;
    }
    setLocalTasks((prev) =>
      prev.map((task) =>
        task.id === taskId ? { ...task, title: editingTitle } : task
      )
    );
    onTaskUpdate?.({
      action: 'edit',
      taskId,
      data: { title: editingTitle },
    });
    setEditingTaskId(null);
    setFormErrors({});
  };

  const handleEditCancel = () => {
    setEditingTaskId(null);
    setEditingTitle('');
    setFormErrors({});
  };

  const handleAddTaskOpen = (columnId: string) => {
    setAddingColumnId(columnId);
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setFormErrors({});
  };

  const handleAddTaskSubmit = async (columnId: string) => {
    const error = validateTitle(newTaskTitle);
    if (error) {
      setFormErrors({ title: error });
      return;
    }
    setIsSubmitting(true);
    try {
      const newTaskId = generateId();
      const newTask: Task = {
        id: newTaskId,
        title: newTaskTitle,
        priority: newTaskPriority,
        column: columnId,
      };
      setLocalTasks((prev) => [...prev, newTask]);
      onTaskUpdate?.({
        action: 'create',
        data: {
          id: newTaskId,
          title: newTaskTitle,
          priority: newTaskPriority,
          column: columnId,
        },
      });
      setSuccessMessage('Task added successfully');
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setAddingColumnId(null);
      setFormErrors({});
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleAddTaskCancel = () => {
    setAddingColumnId(null);
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setFormErrors({});
  };

  const getTasksForColumn = (columnId?: string) =>
    localTasks.filter((task) => task.column === columnId);

  const getPriorityVariant = (priority?: string): 'error' | 'warning' | 'success' =>
    priority === 'high' ? 'error' : priority === 'medium' ? 'warning' : 'success';

  const columnOptions = columns.map((col) => ({
    value: col.id || 'unknown',
    label: col.name || 'Unknown',
  }));

  const totalTasks = localTasks.length;
  const completedTasks = getTasksForColumn(columns[columns.length - 1]?.id).length;

  return (
    <Container maxWidth="full" padding={24} center={false}>
      <Stack direction="vertical" gap={24}>
        <Card
          padding={16}
          shadow="sm"
          border
          style={{ backgroundColor: 'var(--ggui-color-container, #ede9fe)' }}
        >
          <Row justify="between" align="center" gap={24}>
            <Row gap={16} align="center">
              <Text color="var(--ggui-color-onContainer, #4c1d95)" weight="semibold">
                Total: {totalTasks}
              </Text>
              <Divider orientation="vertical" margin={0} />
              <Text color="var(--ggui-color-onContainer, #4c1d95)" weight="semibold">
                Done: {completedTasks}
              </Text>
              <Divider orientation="vertical" margin={0} />
              <Text color="var(--ggui-color-onContainer, #4c1d95)" weight="semibold">
                {totalTasks > 0 ? Math.round((completedTasks / totalTasks) * 100) : 0}%
              </Text>
            </Row>
            {successMessage && (
              <Text color="var(--ggui-color-success-600, #16a34a)" weight="medium" variant="caption">
                ✓ {successMessage}
              </Text>
            )}
          </Row>
        </Card>

        <Stack direction="horizontal" gap={16} align="start" wrap={false}>
          {columns.map((column) => {
            const columnId = column.id || 'unknown';
            const tasksInColumn = getTasksForColumn(columnId);

            return (
              <div
                key={columnId}
                style={{
                  flex: '1 0 300px',
                  minWidth: '300px',
                  backgroundColor: 'var(--ggui-color-surface, #fafafa)',
                  borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                  padding: 'var(--ggui-spacing-2, 8px)',
                }}
              >
                <Stack direction="vertical" gap={12}>
                  <Card
                    padding={12}
                    shadow="none"
                    border
                    style={{
                      backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
                      borderBottom: '2px solid var(--ggui-color-primary-200, #bae6fd)',
                    }}
                  >
                    <Row justify="between" align="center">
                      <Text
                        variant="h3"
                        color="var(--ggui-color-primary-900, #0c4a6e)"
                        weight="semibold"
                      >
                        {column.name || 'Column'}
                      </Text>
                      <Badge variant="primary" size="sm">
                        {tasksInColumn.length}
                      </Badge>
                    </Row>
                  </Card>

                  <Stack direction="vertical" gap={8}>
                    {tasksInColumn.map((task) =>
                      editingTaskId === task.id ? (
                        <Card key={task.id} padding={12} shadow="sm" border
                          style={{ backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)' }}>
                          <Stack direction="vertical" gap={8}>
                            <Input label="Edit" value={editingTitle} onChange={setEditingTitle} placeholder="Title" error={formErrors.title} />
                            <Row gap={8} justify="end">
                              <Button variant="secondary" size="sm" onClick={handleEditCancel}>
                                Cancel
                              </Button>
                              <Button variant="primary" size="sm" onClick={() => handleEditSave(task.id || '')}>
                                Save
                              </Button>
                            </Row>
                          </Stack>
                        </Card>
                      ) : (
                        <Card key={task.id} padding={12} shadow="sm" border
                          style={{
                            backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
                          }}>
                          <Stack direction="vertical" gap={8}>
                            <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)" title="Double-click to edit" onDoubleClick={() => handleEditStart(task)}>
                              {task.title || 'Untitled'}
                            </Text>
                            <Row gap={8} align="center" wrap>
                              {task.priority && (
                                <Badge variant={getPriorityVariant(task.priority)} size="sm">
                                  {task.priority.charAt(0).toUpperCase() + task.priority.slice(1)}
                                </Badge>
                              )}
                              {task.assignee && (
                                <div style={{
                                  width: '28px',
                                  height: '28px',
                                  borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                                  backgroundColor: 'var(--ggui-color-primary-200, #bae6fd)',
                                  display: 'flex',
                                  alignItems: 'center',
                                  justifyContent: 'center',
                                  fontSize: '12px',
                                  fontWeight: '600',
                                  color: 'var(--ggui-color-primary-700, #0369a1)',
                                }} title={`Assigned to ${task.assignee}`}>
                                  {task.assignee.substring(0, 2).toUpperCase()}
                                </div>
                              )}
                              {task.dueDate && (
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" title={`Due ${task.dueDate}`}>
                                  {formatDate(task.dueDate)}
                                </Text>
                              )}
                            </Row>
                            <Row gap={6} justify="end">
                              <Button variant="outline" size="sm" onClick={() => handleEditStart(task)}>
                                Edit
                              </Button>
                              <Select label="Move" value={columnId} onChange={(val) => handleMoveTask(task.id || '', val)} options={columnOptions} />
                            </Row>
                          </Stack>
                        </Card>
                      )
                    )}
                  </Stack>

                  {addingColumnId === columnId ? (
                    <Card padding={12} shadow="sm" border
                      style={{
                        backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
                        borderStyle: 'dashed',
                      }}>
                      <Stack direction="vertical" gap={8}>
                        <Input label="Name" placeholder="Task title" value={newTaskTitle} onChange={setNewTaskTitle} error={formErrors.title} required />
                        <Select label="Priority" value={newTaskPriority} onChange={(val) => setNewTaskPriority(val as 'low' | 'medium' | 'high')} options={[{ value: 'low', label: 'Low' }, { value: 'medium', label: 'Medium' }, { value: 'high', label: 'High' }]} />
                        <Row gap={8} justify="end">
                          <Button variant="secondary" size="sm" onClick={handleAddTaskCancel}>
                            Cancel
                          </Button>
                          <Button variant="primary" size="sm" onClick={() => handleAddTaskSubmit(columnId)} disabled={isSubmitting} loading={isSubmitting}>
                            Add
                          </Button>
                        </Row>
                      </Stack>
                    </Card>
                  ) : (
                    <Button variant="primary" size="sm" fullWidth leftIcon={<Icon name="plus" size={16} />} onClick={() => handleAddTaskOpen(columnId)}>
                      Add Task
                    </Button>
                  )}
                </Stack>
              </div>
            );
          })}
        </Stack>
      </Stack>
    </Container>
  );
}

import { useState, useEffect, useRef } from 'react';
import { Card, Stack, Text, Input, Button, Box, Divider, Badge, Icon, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Props {
  /** Chat window title */
  title?: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages?: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Callback when user sends a message - Send Message action */
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function ChatInterface({
  title = 'Chat',
  currentUser,
  participantCount,
  messages = [],
  onSendMessage,
}: Props) {
  const [inputText, setInputText] = useState<string>('');
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const { motionEnabled } = useMotion();

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const formatTime = (isoTimestamp?: string): string => {
    if (!isoTimestamp) return '';
    const date = new Date(isoTimestamp);
    const now = new Date();
    const diffMs = now.getTime() - date.getTime();
    const diffMins = Math.floor(diffMs / 60000);
    if (diffMins < 1) return 'just now';
    if (diffMins < 60) return `${diffMins}m ago`;
    const diffHours = Math.floor(diffMs / 3600000);
    if (diffHours < 24) return `${diffHours}h ago`;
    return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
  };

  const groupedMessages = messages.reduce(
    (acc, msg, index) => {
      const lastGroup = acc[acc.length - 1];
      if (lastGroup && lastGroup.messages[0].sender === msg.sender && index > 0 && messages[index - 1].sender === msg.sender) {
        lastGroup.messages.push(msg);
      } else {
        acc.push({ messages: [msg], groupIndex: acc.length });
      }
      return acc;
    },
    [] as Array<{ messages: typeof messages; groupIndex: number }>
  );

  const handleSend = () => {
    const trimmed = inputText.trim();
    if (!trimmed) return;
    if (onSendMessage) {
      onSendMessage({ text: trimmed, timestamp: new Date().toISOString() });
    }
    setInputText('');
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const isInputEmpty = inputText.trim().length === 0;

  return (
    <>
      <MotionKeyframes />
      <Card padding={0} shadow="md" border={true} style={{ display: 'flex', flexDirection: 'column', height: '100%', maxHeight: '600px' }}>
        <Stack direction="vertical" gap={0} style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
          <Box padding="var(--ggui-spacing-4, 16px)" background="var(--ggui-color-primary-50, #f0f9ff)" borderRadius="0" style={{ borderBottom: '1px solid var(--ggui-color-primary-200, #bae6fd)', flexShrink: 0, display: 'flex', gap: 'var(--ggui-spacing-2, 8px)', justifyContent: 'space-between', alignItems: 'center' }}>
            <Text variant="h3" weight="bold" color="var(--ggui-color-primary-900, #0c4a6e)">{title}</Text>
            {participantCount !== undefined && (<Badge variant="primary" size="sm" pill={true}>{participantCount} {participantCount === 1 ? 'participant' : 'participants'}</Badge>)}
          </Box>

          <Divider margin={0} orientation="horizontal" />

          <Box padding="var(--ggui-spacing-4, 16px)" background="var(--ggui-color-surface, #fafafa)" style={{ flex: 1, overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: 'var(--ggui-spacing-2, 8px)' }}>
            {groupedMessages.length === 0 ? (
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center" style={{ marginTop: 'auto', marginBottom: 'auto' }}>No messages yet. Start a conversation!</Text>
            ) : (
              groupedMessages.map((group, groupIndex) => {
                const isCurrentUser = group.messages[0].sender === currentUser;
                return (
                  <Stack key={`group-${groupIndex}`} direction="vertical" gap={4} align={isCurrentUser ? 'end' : 'start'} style={{ maxWidth: '75%', alignSelf: isCurrentUser ? 'flex-end' : 'flex-start', animation: motionEnabled ? `${animation.slideInUp}` : 'none', animationDelay: motionEnabled ? `${groupIndex * 30}ms` : '0ms' }}>
                    {group.messages.map((msg, msgIndex) => (
                      <Box key={`msg-${groupIndex}-${msgIndex}`} padding="var(--ggui-spacing-2, 12px)" borderRadius="8" background={isCurrentUser ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'} style={{ display: 'flex', flexDirection: 'column', gap: 'var(--ggui-spacing-1, 4px)' }}>
                        {msgIndex === 0 && !isCurrentUser && (<Text variant="caption" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{msg.sender || 'Unknown'}</Text>)}
                        <Text variant="body" color={isCurrentUser ? 'var(--ggui-color-primary-50, #ffffff)' : 'var(--ggui-color-onSurface, #18181b)'} weight="normal">{msg.text || ''}</Text>
                        <time dateTime={msg.timestamp}><Text variant="caption" color={isCurrentUser ? 'var(--ggui-color-primary-100, #e0f2fe)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}>{formatTime(msg.timestamp)}</Text></time>
                      </Box>
                    ))}
                  </Stack>
                );
              })
            )}
            <div ref={messagesEndRef} style={{ height: 0 }} />
          </Box>

          <Divider margin={0} orientation="horizontal" />

          <Box padding="var(--ggui-spacing-4, 16px)" background="var(--ggui-color-surface, #fafafa)" borderRadius="0" style={{ borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)', flexShrink: 0 }}>
            <Stack direction="vertical" gap={8}>
              <Input label="Message" placeholder="Type a message..." value={inputText} onChange={setInputText} onKeyDown={handleKeyDown} type="text" />
              <div style={{ display: 'flex', gap: 'var(--ggui-spacing-2, 8px)', justifyContent: 'flex-end' }}>
                <Button variant="primary" size="sm" onClick={handleSend} disabled={isInputEmpty} rightIcon={<Icon name="plus" size={16} />}>Send</Button>
              </div>
            </Stack>
          </Box>
        </Stack>
      </Card>
    </>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { Container, Card, Stack, Row, Text, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

// Custom hook for agent data stream (safe encapsulation)
function useAgentDataStream(onData: (data: Stock[]) => void) {
  useEffect(() => {
    const handler = (event: Event) => {
      try {
        const customEvent = event as CustomEvent;
        if (customEvent?.detail && Array.isArray(customEvent.detail.stocks)) {
          onData(customEvent.detail.stocks);
        }
      } catch {
        // Silently handle errors
      }
    };

    // Use optional chaining for safe window access
    const globalScope = globalThis as any;
    if (globalScope?.addEventListener) {
      globalScope.addEventListener('ggui:agent-data', handler);
      return () => globalScope.removeEventListener('ggui:agent-data', handler);
    }
  }, [onData]);
}

export default function StockTickerDashboard({ stocks = [], lastUpdated }: Props) {
  const [displayStocks, setDisplayStocks] = useState<Stock[]>(stocks);
  const [isConnected, setIsConnected] = useState(stocks.length > 0);
  const [isLoading, setIsLoading] = useState(stocks.length === 0);
  const { motionEnabled } = useMotion();

  // Handle incoming agent data stream
  const handleAgentData = useCallback((incomingStocks: Stock[]) => {
    setDisplayStocks(incomingStocks);
    setIsConnected(true);
    setIsLoading(false);
  }, []);

  useAgentDataStream(handleAgentData);

  // Update stocks from props if not streaming
  useEffect(() => {
    if (!isConnected && stocks.length > 0) {
      setDisplayStocks(stocks);
      setIsLoading(false);
    }
  }, [stocks, isConnected]);

  const formatPrice = (price?: number): string => {
    return price !== undefined ? `$${price.toFixed(2)}` : '—';
  };

  const formatChange = (change?: number): string => {
    if (change === undefined) return '—';
    const prefix = change > 0 ? '+' : '';
    return `${prefix}${change.toFixed(2)}`;
  };

  const formatChangePercent = (changePercent?: number): string => {
    if (changePercent === undefined) return '—';
    const prefix = changePercent > 0 ? '+' : '';
    return `${prefix}${changePercent.toFixed(2)}%`;
  };

  const formatTimestamp = (isoTimestamp?: string): string => {
    if (!isoTimestamp) return 'Connecting...';
    try {
      const date = new Date(isoTimestamp);
      return date.toLocaleTimeString();
    } catch {
      return 'Connecting...';
    }
  };

  const getChangeColor = (change?: number): string => {
    if (change === undefined || change === 0) {
      return 'var(--ggui-color-onSurfaceVariant, #52525b)';
    }
    return change > 0
      ? 'var(--ggui-color-success-500, #22c55e)'
      : 'var(--ggui-color-error-500, #ef4444)';
  };

  const getArrowIcon = (change?: number): string => {
    if (change === undefined || change === 0) return '';
    return change > 0 ? '▲' : '▼';
  };

  const getBorderColor = (change?: number): string => {
    if (change === undefined || change === 0) {
      return 'var(--ggui-color-outline, #d4d4d8)';
    }
    return change > 0
      ? 'var(--ggui-color-success-500, #22c55e)'
      : 'var(--ggui-color-error-500, #ef4444)';
  };

  return (
    <>
      <MotionKeyframes />
      <div
        style={{
          backgroundColor: 'var(--ggui-color-surface, #fafafa)',
          minHeight: '100vh',
          padding: 'var(--ggui-spacing-6, 24px)',
        }}
      >
        <Container maxWidth="full" padding={0} center={false}>
          <Stack direction="vertical" gap={24}>
            {/* Header Section */}
            <Stack direction="vertical" gap={8}>
              <Text
                variant="h1"
                weight="bold"
                color="var(--ggui-color-onSurface, #18181b)"
              >
                Market Watch
              </Text>
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Last Updated: {formatTimestamp(lastUpdated)}
              </Text>
            </Stack>

            {/* Loading State */}
            {isLoading && !isConnected && (
              <Text
                variant="body"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
                align="center"
                style={{
                  padding: 'var(--ggui-spacing-8, 32px)',
                }}
              >
                No stocks available. Waiting for data...
              </Text>
            )}

            {/* Stock Cards Grid */}
            {displayStocks.length > 0 && (
              <div
                style={{
                  display: 'grid',
                  gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
                  gap: 'var(--ggui-spacing-4, 16px)',
                }}
              >
                {displayStocks.map((stock, index) => {
                  const changeColor = getChangeColor(stock.change);
                  const arrowIcon = getArrowIcon(stock.change);
                  const borderColor = getBorderColor(stock.change);

                  return (
                    <Card
                      key={stock.symbol || index}
                      padding={16}
                      shadow="sm"
                      border={true}
                      style={{
                        borderLeft: `4px solid ${borderColor}`,
                        animation: motionEnabled
                          ? `${animation.slideInUp}`
                          : 'none',
                        animationDelay: motionEnabled
                          ? `${index * 50}ms`
                          : '0ms',
                        transition: motionEnabled
                          ? 'border-color 200ms ease-out, box-shadow 200ms ease-out'
                          : 'none',
                      }}
                      role="article"
                      aria-label={`Stock: ${stock.symbol || 'Unknown'}, Price: ${formatPrice(stock.price)}, Change: ${formatChange(stock.change)}`}
                    >
                      <Stack direction="vertical" gap={12}>
                        {/* Header: Ticker + Change % */}
                        <Row justify="between" align="center">
                          <Text
                            variant="h2"
                            weight="bold"
                            color="var(--ggui-color-onSurface, #18181b)"
                          >
                            {stock.symbol || '—'}
                          </Text>
                          <Row gap={4} align="center">
                            {arrowIcon && (
                              <Text
                                variant="label"
                                weight="semibold"
                                color={changeColor}
                                aria-label={`Change direction: ${
                                  stock.change > 0 ? 'up' : 'down'
                                }`}
                              >
                                {arrowIcon}
                              </Text>
                            )}
                            <Text
                              variant="label"
                              weight="semibold"
                              color={changeColor}
                            >
                              {formatChangePercent(stock.changePercent)}
                            </Text>
                          </Row>
                        </Row>

                        {/* Company Name */}
                        <Text
                          variant="body"
                          color="var(--ggui-color-onSurfaceVariant, #52525b)"
                        >
                          {stock.name || 'Company Name'}
                        </Text>

                        {/* Price */}
                        <Row gap={8} align="center">
                          <Text
                            variant="label"
                            color="var(--ggui-color-onSurfaceVariant, #52525b)"
                          >
                            Current Price
                          </Text>
                          <Text
                            variant="h3"
                            weight="semibold"
                            color="var(--ggui-color-onSurface, #18181b)"
                          >
                            {formatPrice(stock.price)}
                          </Text>
                        </Row>

                        {/* Change Amount */}
                        <Row gap={8} align="center">
                          <Text
                            variant="label"
                            color="var(--ggui-color-onSurfaceVariant, #52525b)"
                          >
                            Change
                          </Text>
                          <Text
                            variant="body"
                            weight="medium"
                            color={changeColor}
                          >
                            {formatChange(stock.change)}
                          </Text>
                        </Row>
                      </Stack>
                    </Card>
                  );
                })}
              </div>
            )}
          </Stack>
        </Container>
      </div>
    </>
  );
}

