import { Card, Stack, Row, Box, Text, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

const getConditionEmoji = (value: string): string => {
  const normalized = value.toLowerCase();
  if (normalized.includes('sunny') || normalized.includes('clear')) return '☀️';
  if (normalized.includes('cloudy')) return '☁️';
  if (normalized.includes('rainy') || normalized.includes('drizzle')) return '🌧️';
  if (normalized.includes('storm') || normalized.includes('thunder')) return '⛈️';
  if (normalized.includes('snow')) return '❄️';
  return '🌤️';
};

export default function GeneratedComponent({
  city = 'City',
  temperature = 0,
  condition = 'Unknown',
  humidity = 0,
  windSpeed = 0,
  unit = 'C',
  forecast = [{}, {}, {}, {}, {}],
}: Props) {
  const conditionEmoji = getConditionEmoji(condition);

  return (
    <Card
      padding={24}
      shadow="md"
      border
      role="region"
      aria-label={`Weather for ${city}`}
      style={{
        background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
      }}
    >
      <Stack direction="vertical" gap={16}>
        <Row direction="horizontal" justify="between" align="start" gap={12} wrap>
          <Text
            variant="h3"
            weight="semibold"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            {city}
          </Text>

          <Box
            style={{
              background: 'var(--ggui-color-container, #ede9fe)',
              color: 'var(--ggui-color-onContainer, #4c1d95)',
              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
              border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
            }}
          >
            <Row direction="horizontal" align="center" gap={8}>
              <Text variant="body" aria-hidden>
                {conditionEmoji}
              </Text>
              <Text variant="body" color="var(--ggui-color-onContainer, #4c1d95)">
                {condition}
              </Text>
            </Row>
          </Box>
        </Row>

        <Text
          variant="h1"
          weight="bold"
          color="var(--ggui-color-primary-700, #0369a1)"
        >
          {`${temperature}°${unit}`}
        </Text>

        <Row direction="horizontal" gap={12} wrap>
          <Box
            style={{
              flex: 1,
              minWidth: 120,
              background: 'var(--ggui-color-surface, #fafafa)',
              border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              padding: 'var(--ggui-spacing-4, 16px)',
            }}
          >
            <Stack direction="vertical" gap={4}>
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Humidity
              </Text>
              <Text
                variant="body"
                weight="semibold"
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {humidity}%
              </Text>
            </Stack>
          </Box>

          <Box
            style={{
              flex: 1,
              minWidth: 120,
              background: 'var(--ggui-color-surface, #fafafa)',
              border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              padding: 'var(--ggui-spacing-4, 16px)',
            }}
          >
            <Stack direction="vertical" gap={4}>
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Wind
              </Text>
              <Text
                variant="body"
                weight="semibold"
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {windSpeed}
              </Text>
            </Stack>
          </Box>
        </Row>

        <Divider />

        <Box
          style={{
            background: 'var(--ggui-color-surface, #fafafa)',
            border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
            borderRadius: 'var(--ggui-shape-radius-md, 8px)',
            padding: 'var(--ggui-spacing-2, 8px)',
          }}
        >
          <Row direction="horizontal" gap={8} wrap>
            {forecast.slice(0, 5).map((item, index) => {
              const day = item.day ?? `Day ${index + 1}`;
              const icon = item.icon ?? getConditionEmoji(condition);
              const high = item.high ?? '--';
              const low = item.low ?? '--';

              return (
                <Box
                  key={`${day}-${index}`}
                  style={{
                    flex: 1,
                    minWidth: 90,
                    border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    padding: 'var(--ggui-spacing-2, 8px)',
                    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  }}
                >
                  <Stack direction="vertical" gap={4} align="center">
                    <Text
                      variant="caption"
                      weight="medium"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      {day}
                    </Text>
                    <Text variant="body" aria-label={`Forecast icon ${icon}`}>
                      {icon}
                    </Text>
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    >
                      {`${high}° / ${low}°`}
                    </Text>
                  </Stack>
                </Box>
              );
            })}
          </Row>
        </Box>
      </Stack>
    </Card>
  );
}

import { Card, Stack, Row, Text, Box, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent({
  city = '',
  temperature = 0,
  condition = '',
  humidity = 0,
  windSpeed = 0,
  unit = 'C',
  forecast = [],
}: Props) {
  const displayUnit = unit || 'C';
  const safeForecast = forecast.slice(0, 5);

  return (
    <Card
      padding={24}
      shadow="md"
      border
      role="region"
      aria-label={city ? `Weather for ${city}` : 'Weather card'}
      style={{
        background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
        color: 'var(--ggui-color-onSurface, #18181b)',
      }}
    >
      <Stack direction="vertical" gap={16}>
        <Row justify="between" align="start" wrap gap={12}>
          <Stack direction="vertical" gap={4}>
            <Text
              variant="label"
              weight="medium"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {city || '—'}
            </Text>
            <Text
              variant="body"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              {condition || '—'}
            </Text>
          </Stack>

          <Stack direction="vertical" align="end" gap={4}>
            <Box
              padding="var(--ggui-spacing-1, 4px) var(--ggui-spacing-2, 8px)"
              style={{
                background: 'var(--ggui-color-container, #ede9fe)',
                borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              }}
            >
              <Text
                variant="body"
                color="var(--ggui-color-onContainer, #4c1d95)"
                aria-label={`Condition icon ${condition || 'unknown condition'}`}
              >
                {condition || '•'}
              </Text>
            </Box>
            <Text
              variant="h1"
              weight="bold"
              color="var(--ggui-color-primary-600, #0284c7)"
            >
              {`${temperature}°${displayUnit}`}
            </Text>
          </Stack>
        </Row>

        <Row gap={12} wrap>
          <Box
            padding="var(--ggui-spacing-2, 8px)"
            style={{
              flex: 1,
              minWidth: 120,
              background: 'var(--ggui-color-surface, #fafafa)',
              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
            }}
          >
            <Stack direction="vertical" gap={4}>
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Humidity
              </Text>
              <Text
                variant="body"
                weight="semibold"
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {`${humidity}%`}
              </Text>
            </Stack>
          </Box>

          <Box
            padding="var(--ggui-spacing-2, 8px)"
            style={{
              flex: 1,
              minWidth: 120,
              background: 'var(--ggui-color-surface, #fafafa)',
              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
            }}
          >
            <Stack direction="vertical" gap={4}>
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Wind
              </Text>
              <Text
                variant="body"
                weight="semibold"
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {`${windSpeed}`}
              </Text>
            </Stack>
          </Box>
        </Row>

        <Divider margin={0} />

        <Stack direction="vertical" gap={8} aria-label="5-day forecast">
          <Text
            variant="label"
            weight="medium"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            5-Day Forecast
          </Text>

          <Row gap={8} wrap justify="between">
            {safeForecast.map((item, index) => {
              const day = item.day || '—';
              const icon = item.icon || '•';
              const high = item.high ?? '--';
              const low = item.low ?? '--';

              return (
                <Box
