import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Box,
  Heading,
  Divider,
  Badge,
  MotionKeyframes,
  useMotion,
  Spacer
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: ElementData[];
}

const getCategoryColor = (category?: string): string => {
  const cat = category?.toLowerCase() || '';
  if (cat.includes('alkali metal')) return 'var(--ggui-color-error-500, #ef4444)';
  if (cat.includes('alkaline earth')) return 'var(--ggui-color-warning-500, #f59e0b)';
  if (cat.includes('transition metal')) return 'var(--ggui-color-primary-400, #38bdf8)';
  if (cat.includes('post-transition')) return 'var(--ggui-color-success-400, #4ade80)';
  if (cat.includes('metalloid')) return 'var(--ggui-color-success-600, #16a34a)';
  if (cat.includes('noble gas')) return 'var(--ggui-color-info-500, #06b6d4)';
  if (cat.includes('nonmetal')) return 'var(--ggui-color-primary-600, #0284c7)';
  if (cat.includes('lanthanide')) return 'var(--ggui-color-warning-300, #fcd34d)';
  if (cat.includes('actinide')) return 'var(--ggui-color-error-300, #fca5a5)';
  return 'var(--ggui-color-neutral-400, #9ca3af)';
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);
  const { motionEnabled } = useMotion();

  const filteredElements = useMemo(() => {
    if (!searchTerm) return elements;
    const lower = searchTerm.toLowerCase();
    return elements.filter(e => e.name?.toLowerCase().includes(lower) || e.symbol?.toLowerCase().includes(lower));
  }, [elements, searchTerm]);

  const categories = useMemo(() => {
    const set = new Set<string>();
    elements.forEach(e => { if (e.category) set.add(e.category); });
    return Array.from(set).sort();
  }, [elements]);

  return (
    <Container maxWidth="xl" padding={24}>
      <MotionKeyframes />
      <Stack gap={32}>
        <Row justify="between" align="end" wrap>
          <Stack gap={4}>
            <Heading level={1}>Periodic Table</Heading>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">Chemical properties visualization.</Text>
          </Stack>
          <Box style={{ width: '100%', maxWidth: 400 }}>
            <Text variant="label">Search Elements</Text>
            <Input label="Search Elements" placeholder="Find by name..." value={searchTerm} onChange={setSearchTerm} />
          </Box>
        </Row>

        <Card padding={12} border shadow="none">
          <Row gap={16} wrap>
            {categories.map((cat) => (
              <Row key={cat} gap={8} align="center">
                <Box style={{ width: 14, height: 14, borderRadius: 4, background: getCategoryColor(cat) }} />
                <Text variant="caption">{cat}</Text>
              </Row>
            ))}
          </Row>
        </Card>

        <Box style={{ display: 'grid', gridTemplateColumns: 'repeat(18, 1fr)', gap: 4, padding: 16, background: 'var(--ggui-color-surfaceVariant)', borderRadius: 16, border: '1px solid var(--ggui-color-outline)', overflowX: 'auto', minHeight: '500px' }}>
          {elements.map((el) => {
            const isMatch = filteredElements.some(fe => fe.atomicNumber === el.atomicNumber);
            const isSelected = selectedElement?.atomicNumber === el.atomicNumber;
            const catColor = getCategoryColor(el.category);
            return (
              <Box key={el.atomicNumber} onClick={() => setSelectedElement(el)} style={{ gridRow: el.row, gridColumn: el.col, aspectRatio: '1/1', cursor: 'pointer', display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center', position: 'relative', borderRadius: 4, border: isSelected ? '2px solid var(--ggui-color-onSurface)' : '1px solid var(--ggui-color-outline)', background: isSelected ? catColor : 'var(--ggui-color-surface)', color: isSelected ? 'white' : 'var(--ggui-color-onSurface)', opacity: isMatch ? 1 : 0.2, transition: transition.normal, transform: isSelected ? 'scale(1.1)' : 'scale(1)', zIndex: isSelected ? 10 : 1, animation: motionEnabled ? animation.fadeIn : 'none' }}>
                <Text variant="caption" style={{ position: 'absolute', top: 2, left: 4, fontWeight: 500 }}>{el.atomicNumber}</Text>
                <Text weight="bold" style={{ fontSize: '18px', lineHeight: 1, color: isSelected ? 'white' : catColor }}>{el.symbol}</Text>
              </Box>
            );
          })}
        </Box>

        {selectedElement && (
          <Card padding={32} shadow="lg" style={{ animation: motionEnabled ? animation.slideInUp : 'none', borderLeft: `10px solid ${getCategoryColor(selectedElement.category)}` }}>
            <Stack gap={24}>
              <Row justify="between" align="start">
                <Stack gap={8}>
                  <Row gap={16} align="center">
                    <Heading level={1}>{selectedElement.name}</Heading>
                    <Badge variant="primary">{selectedElement.symbol}</Badge>
                  </Row>
                  <Text variant="body">{selectedElement.category}</Text>
                </Stack>
                <Box align="right">
                  <Text weight="bold" style={{ fontSize: '32px' }}>{selectedElement.atomicNumber}</Text>
                  <Text variant="caption">ATOMIC NUMBER</Text>
                </Box>
              </Row>
              <Divider />
              <Row gap={48} wrap>
                <Stack gap={4}>
                  <Text variant="label">Atomic Weight</Text>
                  <Text variant="h2">{selectedElement.atomicWeight} u</Text>
                </Stack>
                <Stack gap={4}>
                  <Text variant="label">Position</Text>
                  <Text variant="h3">Group {selectedElement.col}, Period {selectedElement.row}</Text>
                </Stack>
              </Row>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

