import React, { useState, useEffect, useRef } from 'react';
import {
  Card,
  Stack,
  Row,
  Text,
  Heading,
  Badge,
  TextArea,
  Button,
  Icon,
  Divider,
  Box,
  MotionKeyframes
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Array<Message>;
  sendMessage: (payload: { text: string; timestamp: string }) => void;
}

export default function ChatInterface({
  title = "Chat",
  currentUser = "User",
  participantCount,
  messages: initialMessages = [],
  sendMessage
}: Props) {
  const [messages, setMessages] = useState<Message[]>(initialMessages);
  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => { setMessages(initialMessages); }, [initialMessages]);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleSend = () => {
    const text = inputValue.trim();
    if (!text) return;
    const timestamp = new Date().toISOString();
    setMessages(prev => [...prev, { sender: currentUser, text, timestamp }]);
    if (sendMessage) sendMessage({ text, timestamp });
    setInputValue('');
  };

  return (
    <Card padding={0} shadow="md" style={{ display: 'flex', flexDirection: 'column', height: '600px', maxWidth: '800px', margin: '0 auto', overflow: 'hidden', backgroundColor: 'var(--ggui-color-surface)' }}>
      <MotionKeyframes />
      <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)">
        <Row justify="between" align="center">
          <Stack gap={4}>
            <Heading level={3}>{title}</Heading>
            {participantCount !== undefined && <Badge variant="secondary" size="sm">{participantCount} participants</Badge>}
          </Stack>
          <Button variant="ghost" size="sm" aria-label="Settings"><Icon name="settings" size={18} /></Button>
        </Row>
      </Box>
      <Divider margin={0} />
      <div ref={scrollRef} style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-4)', scrollBehavior: 'smooth' }}>
        <Stack gap={16}>
          {messages.map((msg, idx) => {
            const isMe = msg.sender === currentUser;
            const isConsec = idx > 0 && messages[idx - 1].sender === msg.sender;
            return (
              <Stack key={idx} align={isMe ? 'end' : 'start'} gap={4} style={{ animation: animation.fadeIn, maxWidth: '80%', alignSelf: isMe ? 'flex-end' : 'flex-start' }}>
                {!isMe && !isConsec && <Text variant="label" weight="semibold">{msg.sender}</Text>}
                <Box padding="var(--ggui-spacing-2) var(--ggui-spacing-3)" borderRadius="var(--ggui-shape-radius-lg)" background={isMe ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'} style={{ borderBottomRightRadius: isMe && !isConsec ? 'var(--ggui-spacing-1)' : 'var(--ggui-shape-radius-lg)', borderBottomLeftRadius: !isMe && !isConsec ? 'var(--ggui-spacing-1)' : 'var(--ggui-shape-radius-lg)', color: isMe ? '#fff' : 'inherit' }}>
                  <Text style={{ wordBreak: 'break-word' }}>{msg.text}</Text>
                </Box>
                <Text variant="caption">{msg.timestamp ? new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : ''}</Text>
              </Stack>
            );
          })}
        </Stack>
      </div>
      <Divider margin={0} />
      <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surface)">
        <Stack gap={8}>
          <TextArea
            label="Your Message"
            placeholder="Type here..."
            value={inputValue}
            onChange={setInputValue}
            rows={1}
          />
          <Button variant="primary" onClick={handleSend} disabled={!inputValue.trim()} fullWidth>Send Message</Button>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Select,
  Checkbox,
  RadioGroup,
  Button,
  Divider,
  Box,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Callback */
  onComplete: (data: any) => void;
}

export default function OnboardingWizard(props: Props) {
  const { initialProfile, avatarOptions, roleOptions, onComplete } = props;
  const { motionEnabled } = useMotion();
  const [step, setStep] = useState(1);
  const [data, setData] = useState({
    name: initialProfile?.name || '',
    email: initialProfile?.email || '',
    avatar: initialProfile?.avatar || '',
    role: initialProfile?.role || '',
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme || 'light'
  });

  const step1Valid = data.name && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(data.email) && data.avatar;
  const step2Valid = data.role;

  return (
    <Container maxWidth="md">
      <MotionKeyframes />
      <Stack gap={24}>
        <Row justify="between"><Text variant="label">Step {step} of 3</Text></Row>
        <Card padding={32}>
          <div key={step} style={{ animation: motionEnabled ? animation.fadeIn : 'none' }}>
            {step === 1 && (
              <Stack gap={16}>
                <Text variant="h2">Profile</Text>
                <Stack gap={4}>
                  <Text as="label" htmlFor="name">Name</Text>
                  <Input id="name" label="Name" value={data.name} onChange={v => setData({...data, name: v})} required />
                </Stack>
                <Stack gap={4}>
                  <Text as="label" htmlFor="email">Email</Text>
                  <Input id="email" label="Email" type="email" value={data.email} onChange={v => setData({...data, email: v})} required />
                </Stack>
                <Row gap={8}>
                  {avatarOptions.map(a => (
                    <Button key={a} variant={data.avatar === a ? 'primary' : 'outline'} onClick={() => setData({...data, avatar: a})}>{a}</Button>
                  ))}
                </Row>
              </Stack>
            )}
            {step === 2 && (
              <Stack gap={16}>
                <Text variant="h2">Preferences</Text>
                <Select label="Role" value={data.role} onChange={v => setData({...data, role: v})} options={roleOptions.map(r => ({label: r, value: r}))} />
                <Checkbox label="Notifications" checked={data.emailNotifications} onChange={v => setData({...data, emailNotifications: v})} />
                <RadioGroup label="Theme" value={data.theme} onChange={v => setData({...data, theme: v})} options={[{label:'Light', value:'light'}, {label:'Dark', value:'dark'}]} />
              </Stack>
            )}
            {step === 3 && (
              <Stack gap={16}>
                <Text variant="h2">Review</Text>
                <Box padding={16} background="var(--ggui-color-surfaceVariant)">
                  <Text>Name: {data.name}</Text>
                  <Text>Email: {data.email}</Text>
                  <Text>Avatar: {data.avatar}</Text>
                  <Text>Role: {data.role}</Text>
                </Box>
              </Stack>
            )}
          </div>
          <Divider margin={24} />
          <Row justify="between">
            <Button variant="outline" disabled={step === 1} onClick={() => setStep(step - 1)}>Back</Button>
            {step < 3 ? (
              <Button variant="primary" disabled={step === 1 ? !step1Valid : !step2Valid} onClick={() => setStep(step + 1)}>Next</Button>
            ) : (
              <Button variant="primary" onClick={() => onComplete(data)}>Complete Setup</Button>
            )}
          </Row>
        </Card>
      </Stack>
    </Container>
  );
}

