        <Stack padding={20} gap={16}>
          <Row justify="around">
            <Stack align="center" gap={4}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                HUMIDITY
              </Text>
              <Text weight="semibold" variant="bodyLarge" color="var(--ggui-color-onSurface, #18181b)">
                {humidity}%
              </Text>
            </Stack>
            <Divider orientation="vertical" />
            <Stack align="center" gap={4}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                WIND
              </Text>
              <Text weight="semibold" variant="bodyLarge" color="var(--ggui-color-onSurface, #18181b)">
                {windSpeed} mph
              </Text>
            </Stack>
          </Row>

          <Divider margin={8} />

          {/* Forecast Section */}
          <Stack gap={12}>
            <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              5-Day Forecast
            </Text>
            <Row justify="between" align="center">
              {forecast.map((item, index) => (
                <Stack
                  key={`${item.day}-${index}`}
                  align="center"
                  gap={4}
                  style={{
                    flex: 1,
                    animation: motionEnabled ? animation.slideInUp : 'none',
                    animationDelay: `${index * 50}ms`,
                  }}
                >
                  <Text variant="caption" weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                    {item.day}
                  </Text>
                  <Text style={{ fontSize: 'var(--ggui-font-size-xl, 20px)' }} aria-hidden="true">
                    {item.icon || '☀️'}
                  </Text>
                  <Stack gap={0} align="center">
                    <Text variant="caption" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                      {item.high}°
                    </Text>
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    >
                      {item.low}°
                    </Text>
                  </Stack>
                </Stack>
              ))}
            </Row>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

/**
 * Simple helper to map common weather conditions to emojis if icons aren't provided
 */
function getWeatherEmoji(condition: string): string {
  const c = (condition || '').toLowerCase();
  if (c.includes('sun') || c.includes('clear')) return '☀️';
  if (c.includes('cloud')) return '☁️';
  if (c.includes('rain') || c.includes('shower')) return '🌧️';
  if (c.includes('snow')) return '❄️';
  if (c.includes('storm') || c.includes('thunder')) return '⛈️';
  if (c.includes('fog') || c.includes('mist')) return '🌫️';
  return '⛅';
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Box,
  Badge,
  Divider,
  Icon,
  Button,
  MotionKeyframes
} from '@ggui-ai/design/primitives';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: ElementData[];
}

/**
 * Maps element categories to design system semantic color keys.
 */
const CATEGORY_COLOR_MAP: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
  'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
  'transition metal': 'var(--ggui-color-primary-500, #0ea5e9)',
  'post-transition metal': 'var(--ggui-color-success-600, #16a34a)',
  'metalloid': 'var(--ggui-color-info-500, #06b6d4)',
  'polyatomic nonmetal': 'var(--ggui-color-success-500, #22c55e)',
  'diatomic nonmetal': 'var(--ggui-color-success-400, #4ade80)',
  'noble gas': 'var(--ggui-color-primary-700, #0369a1)',
  'lanthanide': 'var(--ggui-color-primary-200, #bae6fd)',
  'actinide': 'var(--ggui-color-primary-300, #7dd3fc)',
  'unknown': 'var(--ggui-color-outline, #d4d4d8)',
};

const getCategoryColor = (category?: string) => {
  if (!category) return CATEGORY_COLOR_MAP['unknown'];
  const lower = category.toLowerCase();
  for (const key in CATEGORY_COLOR_MAP) {
    if (lower.includes(key)) return CATEGORY_COLOR_MAP[key];
  }
  return CATEGORY_COLOR_MAP['unknown'];
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [search, setSearch] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  // Filter elements based on search input
  const filteredElements = useMemo(() => {
    if (!search) return elements;
    const query = search.toLowerCase();
    return elements.filter(
      (el) =>
        el.name?.toLowerCase().includes(query) ||
        el.symbol?.toLowerCase().includes(query) ||
        el.atomicNumber?.toString() === query
    );
  }, [elements, search]);

  // Unique categories for the legend
  const categories = useMemo(() => {
    const cats = new Set<string>();
    elements.forEach((el) => {
      if (el.category) cats.add(el.category);
    });
    return Array.from(cats).sort();
  }, [elements]);

  // CSS variables for the 18-column grid layout
  const gridStyle: React.CSSProperties = {
    display: 'grid',
    gridTemplateColumns: 'repeat(18, minmax(45px, 1fr))',
    gridAutoRows: 'minmax(60px, auto)',
    gap: 'var(--ggui-spacing-1, 4px)',
    width: '100%',
    padding: 'var(--ggui-spacing-2, 8px)',
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack gap={24}>
        {/* Header Section */}
        <Row justify="between" align="end" wrap>
          <Stack gap={4}>
            <Text variant="h1">Periodic Table</Text>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Select an element to view detailed properties.
            </Text>
          </Stack>
          <Box style={{ minWidth: '280px' }}>
            <Input label="Search Elements" placeholder="Name, symbol, or number..." value={search} onChange={setSearch} />
          </Box>
        </Row>

        <Divider />

        {/* Periodic Grid Container */}
        <Box
          style={{
            overflowX: 'auto',
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
            border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
          }}
        >
          <div style={gridStyle}>
            {elements.map((el) => {
              const elId = el.atomicNumber || 0;
              const isFilteredOut = search && !filteredElements.find(f => f.atomicNumber === elId);
              const isSelected = selectedElement?.atomicNumber === elId;
              const color = getCategoryColor(el.category);

              return (
                <div
                  key={elId}
                  onClick={() => setSelectedElement(el)}
                  role="button"
                  aria-pressed={isSelected}
                  tabIndex={0}
                  onKeyDown={(e) => { if (e.key === 'Enter') setSelectedElement(el); }}
                  style={{
                    gridColumn: el.col,
                    gridRow: el.row,
                    cursor: 'pointer',
                    display: 'flex',
                    flexDirection: 'column',
                    padding: 'var(--ggui-spacing-1, 4px)',
                    border: `1px solid ${isSelected ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-outline, #d4d4d8)'}`,
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    background: isSelected ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-surface, #ffffff)',
                    opacity: isFilteredOut ? 0.3 : 1,
                    transition: 'all 200ms ease',
                    position: 'relative',
                    aspectRatio: '1 / 1.1',
                    minWidth: '45px',
                    boxShadow: isSelected ? '0 0 0 2px var(--ggui-color-primary-600, #0284c7)' : 'none',
                    zIndex: isSelected ? 10 : 1,
                  }}
                >
                  <Text style={{ fontSize: '10px', fontWeight: 'bold', lineHeight: 1 }}>
                    {el.atomicNumber}
                  </Text>
                  <Stack align="center" justify="center" style={{ flex: 1 }}>
                    <Text weight="bold" style={{ fontSize: '16px' }}>
                      {el.symbol}
                    </Text>
                  </Stack>
                  <Box
                    style={{
                      height: '3px',
                      width: '100%',
                      background: color,
                      borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                    }}
                  />
                </div>
              );
            })}
          </div>
        </Box>

        {/* Info Area */}
        <Row gap={24} align="stretch" wrap>
          {/* Detailed Element Info */}
          <Box style={{ flex: '2 1 400px' }}>
            {selectedElement ? (
              <Card padding={24} shadow="md">
                <Stack gap={24}>
                  <Row justify="between" align="start" wrap>
                    <Stack gap={8}>
                      <Badge
                        variant="primary"
                        style={{
                          background: getCategoryColor(selectedElement.category),
                          color: 'var(--ggui-color-surface, #ffffff)',
                          width: 'fit-content'
                        }}
                      >
                        {selectedElement.category}
                      </Badge>
                      <Text variant="h1" style={{ fontSize: 'var(--ggui-font-size-4xl, 36px)' }}>
                        {selectedElement.name}
                      </Text>
                    </Stack>
                    <Box
                      style={{
                        padding: 'var(--ggui-spacing-4, 16px)',
                        border: '2px solid var(--ggui-color-outline, #d4d4d8)',
                        borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                        textAlign: 'center',
                        minWidth: '100px',
                        background: 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                      }}
                    >
                      <Text variant="caption" weight="semibold">
                        {selectedElement.atomicNumber}
                      </Text>
                      <Text variant="h1" style={{ margin: 0, fontSize: 'var(--ggui-font-size-3xl, 30px)' }}>
                        {selectedElement.symbol}
                      </Text>
                    </Box>
                  </Row>

                  <Divider />

                  <Row gap={48} wrap>
                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Atomic Weight</Text>
                      <Text variant="h3">{selectedElement.atomicWeight} u</Text>
                    </Stack>
                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Position</Text>
                      <Text variant="h3">Row {selectedElement.row}, Col {selectedElement.col}</Text>
                    </Stack>
                  </Row>

                  <Row justify="end">
                    <Button variant="outline" size="sm" onClick={() => setSelectedElement(null)}>Close</Button>
                  </Row>
                </Stack>
              </Card>
            ) : (
              <Card
                padding={24}
                style={{
                  height: '100%',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  border: '2px dashed var(--ggui-color-outline, #d4d4d8)',
                  background: 'transparent'
                }}
              >
                <Stack align="center" gap={12}>
                  <Icon name="search" size={40} color="var(--ggui-color-outlineVariant, #e4e4e7)" />
                  <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">
                    Click an element to see details
                  </Text>
                </Stack>
              </Card>
            )}
          </Box>

          {/* Legend */}
          <Box style={{ flex: '1 1 250px' }}>
            <Card padding={20}>
              <Stack gap={12}>
                <Text variant="label" weight="bold">Categories</Text>
                <Stack gap={8}>
                  {categories.map((cat) => (
                    <Row key={cat} gap={8} align="center">
                      <Box
                        style={{
                          width: '12px',
                          height: '12px',
                          borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                          background: getCategoryColor(cat),
                          flexShrink: 0
                        }}
                      />
                      <Text variant="caption">{cat}</Text>
                    </Row>
                  ))}
                </Stack>
              </Stack>
            </Card>
          </Box>
        </Row>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import {
  Card,
  Stack,
  Text,
  TextArea,
  Button,
  Box,
  Badge,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Message[];
  sendMessage: (payload: { text: string; timestamp: string }) => void;
}

/**
 * Chat component.
 */
export default function GeneratedComponent(props: Props) {
  const { title = 'Chat', currentUser = 'User', messages = [], participantCount, sendMessage } = props;
  const [inputValue, setInputValue] = useState('');
  const [localMessages, setLocalMessages] = useState<Message[]>(messages || []);
  const scrollRef = useRef<HTMLDivElement>(null);
  const { motionEnabled } = useMotion();

  useEffect(() => {
    const handler = (e: any) => {
      if (e.detail) {
        const incoming = Array.isArray(e.detail) ? e.detail : [e.detail];
        setLocalMessages(prev => [...prev, ...incoming]);
      }
    };
    if (typeof globalThis !== 'undefined') {
      globalThis.addEventListener('ggui:agent-data', handler);
      return () => globalThis.removeEventListener('ggui:agent-data', handler);
    }
  }, []);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [localMessages]);

  const onSend = () => {
    if (!inputValue.trim()) return;
    const payload = { text: inputValue.trim(), timestamp: new Date().toISOString() };
    if (sendMessage) sendMessage(payload);
    setLocalMessages(prev => [...prev, { ...payload, sender: currentUser }]);
    setInputValue('');
  };

  return (
    <Box padding="var(--ggui-spacing-4, 16px)">
      <MotionKeyframes />
      <Card padding="var(--ggui-spacing-4, 16px)" shadow="md">
        <Stack gap={16}>
          <Box style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)', paddingBottom: 'var(--ggui-spacing-2, 8px)' }}>
            <Text variant="h3" weight="bold">{title}</Text>
          </Box>

          <Box ref={scrollRef} style={{ height: '300px', overflowY: 'auto', background: 'var(--ggui-color-surfaceVariant, #f4f4f5)', padding: 'var(--ggui-spacing-4, 16px)', borderRadius: 'var(--ggui-shape-radius-md, 8px)' }}>
            <Stack gap={12}>
              {localMessages.map((m, i) => (
                <Box key={i} style={{ 
                  alignSelf: m.sender === currentUser ? 'flex-end' : 'flex-start',
                  backgroundColor: m.sender === currentUser ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surface, #fafafa)',
                  color: m.sender === currentUser ? 'var(--ggui-color-surface, #ffffff)' : 'var(--ggui-color-onSurface, #18181b)',
                  padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
                  borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                  animation: motionEnabled ? animation.slideInUp : 'none'
                }}>
                  <Text style={{ color: 'inherit' }}>{m.text}</Text>
                </Box>
              ))}
            </Stack>
          </Box>

          <Stack gap={8}>
            <Text as="label" htmlFor="msg-text-area" variant="label">Message Label</Text>
            <TextArea 
              label="Message Label" 
              id="msg-text-area" 
              rows={2} 
              value={inputValue} 
              onChange={setInputValue} 
            />
            <Button onClick={onSend} variant="primary" disabled={!inputValue.trim()} fullWidth>
              Send Message
            </Button>
          </Stack>
        </Stack>
      </Card>
    </Box>
  );
}

