import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Icon,
  Badge,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Props {
  lastUpdated?: string;
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const { stocks = [], lastUpdated } = props;
  const [localStocks, setLocalStocks] = useState(stocks);
  const [localUpdated, setLocalUpdated] = useState(lastUpdated || new Date().toISOString());
  const [isLive, setIsLive] = useState(false);
  const { motionEnabled } = useMotion();

  useEffect(() => {
    const handleStream = (event: any) => {
      const data = event.detail;
      if (data && data.stocks) {
        setLocalStocks(data.stocks);
        if (data.lastUpdated) setLocalUpdated(data.lastUpdated);
        setIsLive(true);
      }
    };

    // Listening for 'ggui:agent-data' per Stream Contract
    if (typeof addEventListener !== 'undefined') {
      addEventListener('ggui:agent-data', handleStream);
      return () => removeEventListener('ggui:agent-data', handleStream);
    }
  }, []);

  useEffect(() => {
    if (stocks.length > 0) setLocalStocks(stocks);
    if (lastUpdated) setLocalUpdated(lastUpdated);
  }, [stocks, lastUpdated]);

  const formatDate = (val?: string) => {
    if (!val) return '...';
    try {
      const d = new Date(val);
      return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
    } catch (e) {
      return val;
    }
  };

  const currentStocks = localStocks.length > 0 ? localStocks : [
    { symbol: 'AAPL', name: 'Apple Inc.', price: 175.43, change: 1.25, changePercent: 0.72 },
    { symbol: 'TSLA', name: 'Tesla, Inc.', price: 168.32, change: -4.12, changePercent: -2.39 },
    { symbol: 'NVDA', name: 'NVIDIA Corp.', price: 890.12, change: 15.40, changePercent: 1.76 }
  ];

  return (
    <Container padding="var(--ggui-spacing-6, 24px)" maxWidth="xl">
      <MotionKeyframes />
      <Stack gap={24}>
        <Row justify="between" align="center" wrap gap={16}>
          <Stack gap={4}>
            <Text variant="h1" weight="bold">Market Watch</Text>
            <Row align="center" gap={8}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Last Updated: {formatDate(localUpdated)}
              </Text>
              {isLive && <Badge variant="success" size="sm" pill>LIVE</Badge>}
            </Row>
          </Stack>
        </Row>

        <div className="stock-grid" style={{ display: 'grid', gridTemplateColumns: 'repeat(1, 1fr)', gap: 'var(--ggui-spacing-4, 16px)', width: '100%' }}>
          <style>{`
            @media (min-width: 1024px) { .stock-grid { grid-template-columns: repeat(3, 1fr) !important; } }
            @media (min-width: 768px) and (max-width: 1023px) { .stock-grid { grid-template-columns: repeat(2, 1fr) !important; } }
          `}</style>

          {currentStocks.map((s, idx) => {
            const up = (s.change ?? 0) >= 0;
            const c = up ? 'var(--ggui-color-success-600, #16a34a)' : 'var(--ggui-color-error-600, #dc2626)';
            const b = up ? 'var(--ggui-color-success-500, #22c55e)' : 'var(--ggui-color-error-500, #ef4444)';
            const bg = up ? 'var(--ggui-color-success-50, #f0fdf4)' : 'var(--ggui-color-error-50, #fef2f2)';

            return (
              <Card key={s.symbol || idx} padding={24} shadow="sm" border style={{
                animation: motionEnabled ? animation.fadeIn : 'none',
                animationDelay: `${idx * 40}ms`,
                borderLeft: '4px solid ' + b,
                background: 'var(--ggui-color-surface, #ffffff)',
                transition: 'transform 0.2s ease'
              }}>
                <Stack gap={20}>
                  <Stack gap={2}>
                    <Text variant="h3" weight="bold" style={{ fontSize: 'var(--ggui-font-size-2xl, 24px)' }}>{s.symbol || '---'}</Text>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{s.name || 'Company Name'}</Text>
                  </Stack>
                  <Text variant="h2" weight="bold" style={{ fontSize: 'var(--ggui-font-size-3xl, 30px)', color: 'var(--ggui-color-onSurface, #18181b)' }}>
                    ${(s.price ?? 0).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                  </Text>
                  <Row gap={12} align="center">
                    <Text variant="body" weight="bold" style={{ color: c }}>{up ? '+' : ''}{(s.change ?? 0).toFixed(2)}</Text>
                    <Row gap={4} align="center" style={{ 
                      color: c, 
                      padding: 'var(--ggui-spacing-1, 4px) var(--ggui-spacing-2, 8px)', 
                      borderRadius: 'var(--ggui-shape-radius-md, 8px)', 
                      backgroundColor: bg 
                    }}>
                      <Icon name={up ? 'chevron-up' : 'chevron-down'} size={16} />
                      <Text weight="bold" style={{ fontSize: 'var(--ggui-font-size-sm, 14px)' }}>{(s.changePercent ?? 0).toFixed(2)}%</Text>
                    </Row>
                  </Row>
                </Stack>
              </Card>
            );
          })}
        </div>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Select,
  Checkbox,
  Button,
  Divider,
  Box,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: { 
    name?: string; 
    email?: string; 
    avatar?: string; 
    role?: string; 
    emailNotifications?: boolean; 
    theme?: string 
  };
  onComplete: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const { avatarOptions, roleOptions, initialProfile, onComplete } = props;
  const { motionEnabled } = useMotion();
  const [step, setStep] = useState(0);

  const [name, setName] = useState(initialProfile?.name || '');
  const [email, setEmail] = useState(initialProfile?.email || '');
  const [avatar, setAvatar] = useState(initialProfile?.avatar || (avatarOptions && avatarOptions[0]) || '');
  const [role, setRole] = useState(initialProfile?.role || '');
  const [notifications, setNotifications] = useState(initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState(initialProfile?.theme || 'light');

  const [errors, setErrors] = useState<Record<string, string>>({});

  const validateStep1 = () => {
    const e: Record<string, string> = {};
    if (!name.trim()) e.name = 'Required';
    if (!email.trim() || !email.includes('@')) e.email = 'Invalid';
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const handleNext = () => {
    if (step === 0 && !validateStep1()) return;
    setStep(s => s + 1);
  };

  const handleBack = () => setStep(s => s - 1);
  const handleComplete = () => onComplete && onComplete({ name, email, avatar, role, emailNotifications: notifications, theme });

  const progress = ((step + 1) / 3) * 100;

  return (
    <Container maxWidth="md">
      <MotionKeyframes />
      <Stack gap={24}>
        <Card padding={16}>
          <Stack gap={8}>
            <Row justify="between"><Text variant="label">Step {step + 1}</Text><Text weight="bold">Setup</Text></Row>
            <div style={{ height: 8, background: 'var(--ggui-color-outlineVariant)', borderRadius: 4, overflow: 'hidden' }}>
              <div style={{ height: '100%', width: `${progress}%`, background: 'var(--ggui-color-primary-600)', transition: transition.normal }} />
            </div>
          </Stack>
        </Card>

        <Card padding={32} style={{ animation: motionEnabled ? animation.fadeIn : 'none' }} key={step}>
          {step === 0 && (
            <Stack gap={20}>
              <Text variant="h2">Profile Setup</Text>
              <Input label="Name" value={name} onChange={setName} error={errors.name} required />
              <Input label="Email" value={email} onChange={setEmail} error={errors.email} required />
              <Row gap={8}>
                {avatarOptions?.map(o => (
                  <Button key={o} variant={avatar === o ? 'primary' : 'outline'} onClick={() => setAvatar(o)}>{o}</Button>
                ))}
              </Row>
            </Stack>
          )}

          {step === 1 && (
            <Stack gap={20}>
              <Text variant="h2">Preferences</Text>
              <Select label="Role" value={role} onChange={setRole} options={roleOptions?.map(r => ({ label: r, value: r })) || []} />
              <Checkbox label="Email Notifications" checked={notifications} onChange={setNotifications} />
              <Row gap={8}>
                <Button variant={theme === 'light' ? 'primary' : 'outline'} onClick={() => setTheme('light')}>Light</Button>
                <Button variant={theme === 'dark' ? 'primary' : 'outline'} onClick={() => setTheme('dark')}>Dark</Button>
              </Row>
            </Stack>
          )}

          {step === 2 && (
            <Stack gap={20}>
              <Text variant="h2">Confirm</Text>
              <Box background="var(--ggui-color-surfaceVariant)" padding={20} borderRadius={12}>
                <Text weight="bold">{avatar} {name}</Text>
                <Divider />
                <Text>Email: {email}</Text>
                <Text>Role: {role}</Text>
                <Text>Theme: {theme}</Text>
              </Box>
            </Stack>
          )}
        </Card>

        <Row justify="between">
          <Button variant="outline" disabled={step === 0} onClick={handleBack}>Back</Button>
          {step < 2 ? (
            <Button variant="primary" onClick={handleNext} disabled={step === 0 && (!name || !email)}>Next</Button>
          ) : (
            <Button variant="primary" onClick={handleComplete}>Complete Setup</Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
